namespace BgControls.Windows.Input.Touch;/// <summary>/// 点击操作辅助类，用于处理点击、长按及其状态机流转逻辑./// </summary>internal class TapHelper{    /// <summary>    /// 内部点击状态枚举.    /// </summary>    private enum TapState    {        /// <summary>        /// 手势从未开始.        /// </summary>        NeverStarted,        /// <summary>        /// 触控指示器动画播放中.        /// </summary>        TouchIndicatorAnimating,        /// <summary>        /// 进入长按（点击并按住）状态.        /// </summary>        TapAndHold,        /// <summary>        /// 无效状态.        /// </summary>        Invalid,        /// <summary>        /// 已完成状态.        /// </summary>        Finished,    }    private int touchId;    private UIElement element;    private TouchEventArgs touchDownEventArgs;    private Point touchDownPosition;    private bool isTapTimeValid;    private TapState state;    private bool isWillingTransition;    private TapGestureRecognizer? recognizer;    private GestureDeactivationToken? gestureToken;    /// <summary>    /// Initializes a new instance of the <see cref="TapHelper"/> class.    /// </summary>    /// <param name="args">手势识别器事件参数.</param>    /// <param name="recognizer">关联的点击手势识别器.</param>    public TapHelper(GestureRecognizerEventArgs args, TapGestureRecognizer recognizer)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        ArgumentNullException.ThrowIfNull(recognizer, nameof(recognizer));        this.element = args.Element;        this.touchId = args.TouchId;        this.isTapTimeValid = true;        this.touchDownPosition = args.Position;        this.touchDownEventArgs = args.TouchEventArgs;        this.recognizer = recognizer;    }    /// <summary>    /// Gets 触控 ID.    /// </summary>    internal int TouchId => this.touchId;    /// <summary>    /// Gets or sets 手势当前的状态.    /// </summary>    private TapState State    {        get        {            return this.state;        }        set        {            if (this.state != value)            {                this.state = value;                // 当状态发生变化时触发通知逻辑.                this.OnStateChanged();            }        }    }    /// <summary>    /// 响应触控按下事件.    /// </summary>    /// <param name="args">触控参数.</param>    /// <param name="startTouchIndicator">是否启动触控指示器.</param>    public void OnTouchDown(GestureRecognizerEventArgs args, bool startTouchIndicator)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        if (this.State == TapState.NeverStarted)        {            // 检查是否可以激活点击待定手势.            if (!GestureManager.CanActivateGesture(this.element, TouchManager.TapPendingGestureName))            {                this.TryGoToInvalidState();                return;            }            this.State = TapState.TouchIndicatorAnimating;            // 激活手势并注册强制完成的回调.            this.gestureToken = GestureManager.ActivateGesture(this.element, TouchManager.TapPendingGestureName, this.OnForcedFinish);            // 注册全局脉冲监听并添加长按关联逻辑.            TouchManager.AddTouchPulseEventHandler(this.element, this.OnTouchPulse);            TapAndHoldUtilities.AddTapAndHoldAssociation(this.touchId, this.element, args.Position, startTouchIndicator);        }        else        {            this.TryGoToInvalidState();        }    }    /// <summary>    /// 响应触控移动事件.    /// </summary>    /// <param name="args">触控参数.</param>    public void OnTouchMove(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        // 如果手指移动超出了点击触发的矩形范围，则判定手势无效.        if (!this.IsInsideTapRect(this.touchDownPosition, args.Position))        {            this.TryGoToInvalidState();            TapAndHoldUtilities.CeaseTapAndHold(this.touchId);        }    }    /// <summary>    /// 响应触控抬起事件.    /// </summary>    /// <param name="args">触控参数.</param>    public void OnTouchUp(GestureRecognizerEventArgs args)    {        ArgumentNullException.ThrowIfNull(args, nameof(args));        // 停止长按指示逻辑.        TapAndHoldUtilities.CeaseTapAndHold(this.touchId);        // 如果抬起位置仍在有效范围内，则处理对应的点击或长按抬起逻辑.        if (this.IsInsideTapRect(this.touchDownPosition, args.Position))        {            this.HandleTap(args);            this.HandleTapHoldAndRelease(args);        }        this.FinishTapGestures();    }    /// <summary>    /// 响应触控离开事件.    /// </summary>    public void OnTouchLeave()    {        this.FinishTapGestures();    }    /// <summary>    /// 响应长按计时器周期到达的逻辑.    /// </summary>    /// <param name="pulse">长按计时器脉冲信息.</param>    public void OnTapAndHoldTimerTick(TapAndHoldTimerTickPulse pulse)    {        ArgumentNullException.ThrowIfNull(pulse, nameof(pulse));        this.isTapTimeValid = false;        // 如果处于指示器动画中且手势未被处理，则尝试转换为长按状态.        if (this.State == TapState.TouchIndicatorAnimating &&            !pulse.TapAndHoldHandled &&            GestureManager.CanActivateGesture(this.element, TouchManager.TapAndHoldGestureName))        {            this.State = TapState.TapAndHold;            this.isWillingTransition = true;            this.gestureToken = GestureManager.ActivateGesture(this.element, TouchManager.TapAndHoldGestureName, this.OnForcedFinish);            this.isWillingTransition = false;            // 触发点击并按住事件.            TouchManager.RaiseTapAndHoldEvent(this.element, this.touchDownEventArgs, out var isHandled);            pulse.TapAndHoldHandled = isHandled;        }    }    /// <summary>    /// 停止手势处理.    /// </summary>    public void CeaseGesture()    {        this.FinishTapGestures();    }    /// <summary>    /// 处理点击手势触发.    /// </summary>    private void HandleTap(GestureRecognizerEventArgs args)    {        if (this.State == TapState.TouchIndicatorAnimating &&            this.isTapTimeValid &&            GestureManager.CanActivateGesture(this.element, TouchManager.TapGestureName))        {            this.isWillingTransition = true;            this.gestureToken = GestureManager.ActivateGesture(this.element, TouchManager.TapGestureName, this.FinishTapGestures);            this.isWillingTransition = false;            // 通知识别器触发点击事件并结束手势.            this.recognizer?.RaiseTapEvent(args.TouchEventArgs, args.Position);            args.Handled = true;            this.FinishTapGestures();        }    }    /// <summary>    /// 处理长按后抬起的触发逻辑.    /// </summary>    private void HandleTapHoldAndRelease(GestureRecognizerEventArgs args)    {        if (this.State == TapState.TapAndHold &&            !this.isTapTimeValid &&            GestureManager.CanActivateGesture(this.element, TouchManager.TapHoldAndReleaseGestureName))        {            this.isWillingTransition = true;            this.gestureToken = GestureManager.ActivateGesture(this.element, TouchManager.TapHoldAndReleaseGestureName, this.FinishTapGestures);            this.isWillingTransition = false;            // 触发点击按住并抬起事件.            TouchManager.RaiseTapHoldAndReleaseEvent(this.element, args.TouchEventArgs);            args.Handled = true;            this.FinishTapGestures();        }    }    /// <summary>    /// 标记手势为完成状态.    /// </summary>    private void FinishTapGestures()    {        this.State = TapState.Finished;    }    /// <summary>    /// 响应手势被系统强制终止的回调.    /// </summary>    private void OnForcedFinish()    {        // 如果不是主动触发的状态转换，则发送强制结束脉冲.        if (!this.isWillingTransition)        {            TouchManager.RaiseTouchPulseEvent(this.element, new FinishTapGesturesForciblyPulse());        }    }    /// <summary>    /// 响应触控脉冲事件处理.    /// </summary>    private void OnTouchPulse(object sender, TouchPulseEventArgs args)    {        // 检查脉冲信息类型.        if (args.Info is TapAndHoldTimerTickPulse timerPulse && timerPulse.TouchId == this.touchId)        {            this.OnTapAndHoldTimerTick(timerPulse);        }        else if (args.Info is FinishTapGesturesForciblyPulse)        {            this.TryGoToInvalidState();        }    }    /// <summary>    /// 判断当前位置是否在点击有效的阈值范围内.    /// </summary>    private bool IsInsideTapRect(Point startPosition, Point currentPosition)    {        double distance = MathUtilities.CalculateDistance(startPosition, currentPosition);        return distance <= TouchManager.TapVicinity;    }    /// <summary>    /// 尝试进入无效状态.    /// </summary>    private void TryGoToInvalidState()    {        if (this.State == TapState.TapAndHold || this.State == TapState.TouchIndicatorAnimating)        {            this.State = TapState.Invalid;        }    }    /// <summary>    /// 当手势状态发生变化时的清理逻辑.    /// </summary>    private void OnStateChanged()    {        // 如果手势结束或失效，清理注册的资源.        if (this.State == TapState.Finished || this.State == TapState.Invalid)        {            if (this.gestureToken != null)            {                this.gestureToken.DeactivateGesture();                this.gestureToken = null;            }            TouchManager.RemoveTouchPulseEventHandler(this.element, this.OnTouchPulse);            TapAndHoldUtilities.RemoveTapAndHoldAssociation(this.touchId, this.element);        }        // 如果手势已完成，解除辅助类与识别器的绑定.        if (this.State == TapState.Finished && this.recognizer != null)        {            this.recognizer.ReleaseTapHelper(this);            this.recognizer = null;        }    }}